"use client";

import React, { useState, useEffect, useMemo, useRef } from "react";
import {
  Utensils,
  Home,
  Car,
  Film,
  BookOpen,
  Coins,
  TrendingUp,
  TrendingDown,
  Wallet,
  Percent,
  Bot,
  Sparkles,
  Plus,
  Search,
  Trash2,
  Edit3,
  Sliders,
  Download,
  Wifi,
  WifiOff,
  DownloadCloud,
  CheckCircle,
  Calendar,
  ArrowRight,
  ChevronRight,
  Info,
  AlertTriangle,
  X,
  Send,
  Check,
  PlusCircle,
  FileText,
  Award,
  User as UserIcon,
  LogOut,
  ChevronLeft,
  ShoppingBag,
  Coffee,
  Heart,
  Tv,
  Gift,
  Compass,
  Cpu,
  Gamepad2,
  Activity,
  Briefcase,
  Bell
} from "lucide-react";
import { AreaChart, BarChart, DonutChart } from "@tremor/react";

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Transaction, Budget, CategoryName, AIMessage, TransactionType, User, Badge, CategoryInfo } from "@/lib/types";
import { CATEGORIES, INITIAL_TRANSACTIONS, INITIAL_BUDGETS } from "@/lib/mockData";

// Curated vibrant color options for custom categories
const COLOR_OPTIONS = [
  { name: "Rose", hex: "#f43f5e", bg: "bg-rose-500", text: "text-rose-400", bgLight: "bg-rose-50/70", bgDark: "bg-rose-950/20" },
  { name: "Blue", hex: "#3b82f6", bg: "bg-blue-500", text: "text-blue-400", bgLight: "bg-blue-50/70", bgDark: "bg-blue-950/20" },
  { name: "Amber", hex: "#eab308", bg: "bg-amber-500", text: "text-amber-400", bgLight: "bg-amber-50/70", bgDark: "bg-amber-950/20" },
  { name: "Purple", hex: "#a855f7", bg: "bg-purple-500", text: "text-purple-400", bgLight: "bg-purple-50/70", bgDark: "bg-purple-950/20" },
  { name: "Emerald", hex: "#10b981", bg: "bg-emerald-500", text: "text-emerald-400", bgLight: "bg-emerald-50/70", bgDark: "bg-emerald-950/20" },
  { name: "Violet", hex: "#8b5cf6", bg: "bg-violet-500", text: "text-violet-400", bgLight: "bg-violet-50/70", bgDark: "bg-violet-950/20" },
  { name: "Orange", hex: "#f97316", bg: "bg-orange-500", text: "text-orange-400", bgLight: "bg-orange-50/70", bgDark: "bg-orange-950/20" },
  { name: "Pink", hex: "#ec4899", bg: "bg-pink-500", text: "text-pink-400", bgLight: "bg-pink-50/70", bgDark: "bg-pink-950/20" },
  { name: "Cyan", hex: "#06b6d4", bg: "bg-cyan-500", text: "text-cyan-400", bgLight: "bg-cyan-50/70", bgDark: "bg-cyan-950/20" },
  { name: "Teal", hex: "#14b8a6", bg: "bg-teal-500", text: "text-teal-400", bgLight: "bg-teal-50/70", bgDark: "bg-teal-950/20" }
];

const ICON_OPTIONS = [
  "Utensils", "Home", "Car", "Film", "BookOpen", "Coins",
  "ShoppingBag", "Coffee", "Heart", "Tv", "Gift", "Compass", "Cpu", "Gamepad2", "Activity", "Briefcase"
];

// Badge achievements templates
const BADGE_TEMPLATES = [
  { id: "swiggy", title: "Swiggy Slayer", description: "Keep Food spending under 80% of budget", icon: "Utensils", color: "from-rose-500 to-red-600", requirement: "Food spending <= 80%" },
  { id: "metro", title: "Metro Master", description: "Keep Travel spending under 80% of budget", icon: "Car", color: "from-amber-400 to-yellow-600", requirement: "Travel spending <= 80%" },
  { id: "scholar", title: "Scholar Investor", description: "Spend Γé╣500 or more on Academics", icon: "BookOpen", color: "from-emerald-400 to-teal-600", requirement: "Academics >= Γé╣500" },
  { id: "savings", title: "Savings Sensei", description: "Maintain a savings rate of 35% or higher", icon: "TrendingUp", color: "from-blue-500 to-indigo-600", requirement: "Savings Rate >= 35%" },
  { id: "habitual", title: "Habitual Logger", description: "Log 8 or more transactions", icon: "Coins", color: "from-purple-500 to-fuchsia-600", requirement: "8+ transactions logged" },
  { id: "ninja", title: "Budget Ninja", description: "Maintain all category spending within budget", icon: "Sliders", color: "from-cyan-400 to-blue-600", requirement: "All budgets kept <= 100%" }
];

export default function SmartSpendApp() {
  const [isMounted, setIsMounted] = useState(false);

  // --- Auth / Onboarding / Profile State ---
  const [user, setUser] = useState<User | null>(null);
  const [onboardingStep, setOnboardingStep] = useState(0);
  const [authMode, setAuthMode] = useState<"landing" | "email_login" | "email_signup" | "google_mock">("landing");

  // Login form state
  const [loginEmail, setLoginEmail] = useState("");
  const [loginPassword, setLoginPassword] = useState("");

  // Register form state
  const [regName, setRegName] = useState("");
  const [regCollege, setRegCollege] = useState("");
  const [regEmail, setRegEmail] = useState("");
  const [regPassword, setRegPassword] = useState("");
  const [regAllowance, setRegAllowance] = useState(6000);

  // Custom Category State
  const [categories, setCategories] = useState<Record<string, CategoryInfo>>(CATEGORIES);
  const [showCategoryManager, setShowCategoryManager] = useState(false);
  const [showCategoryBuilder, setShowCategoryBuilder] = useState(false);
  const [newCatName, setNewCatName] = useState("");
  const [newCatColor, setNewCatColor] = useState(COLOR_OPTIONS[0]);
  const [newCatIcon, setNewCatIcon] = useState(ICON_OPTIONS[6]); // default: ShoppingBag

  // Core App states
  const [activeTab, setActiveTab] = useState<"dashboard" | "transactions" | "budget" | "reports" | "ai">("dashboard");
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [budgets, setBudgets] = useState<Budget[]>([]);
  const [offlineMode, setOfflineMode] = useState(false);
  const [isInstalled, setIsInstalled] = useState(false);
  const [showInstallPrompt, setShowInstallPrompt] = useState(false);

  // Notifications State
  const [toast, setToast] = useState<{ message: string; type: "success" | "info" | "warning" } | null>(null);
  const [pushNotification, setPushNotification] = useState<{
    category: string;
    title: string;
    message: string;
    type: "warning" | "alert";
  } | null>(null);

  // Modals state
  const [showAddModal, setShowAddModal] = useState(false);
  const [activeEditingTransaction, setActiveEditingTransaction] = useState<Transaction | null>(null);

  // Search & Filter
  const [searchQuery, setSearchQuery] = useState("");
  const [filterCategory, setFilterCategory] = useState<string>("All");
  const [filterType, setFilterType] = useState<"all" | "income" | "expense">("all");

  // Form states
  const [formAmount, setFormAmount] = useState("");
  const [formCategory, setFormCategory] = useState<string>("Food");
  const [formType, setFormType] = useState<TransactionType>("expense");
  const [formNote, setFormNote] = useState("");
  const [formDate, setFormDate] = useState("2026-06-15");
  const [formRecurring, setFormRecurring] = useState(false);

  // AI Chat states
  const [aiQuery, setAiQuery] = useState("");
  const [aiMessages, setAiMessages] = useState<AIMessage[]>([]);
  const [isAiTyping, setIsAiTyping] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Mock Google Authentication accounts list
  const googleAccounts = [
    { name: "Aarav Mehta", email: "aarav.mehta@iitd.ac.in", college: "IIT Delhi", allowance: 8000 },
    { name: "Ananya Sharma", email: "ananya.s@bits-pilani.ac.in", college: "BITS Pilani", allowance: 12000 },
    { name: "Rohan Gupta", email: "rohan.g@dtu.ac.in", college: "Delhi Technological University", allowance: 6000 }
  ];

  // --- Initial Mount & LocalStorage load ---
  useEffect(() => {
    setIsMounted(true);

    const savedUser = localStorage.getItem("ss_user");
    if (savedUser) {
      try {
        setUser(JSON.parse(savedUser));
      } catch (e) {
        localStorage.removeItem("ss_user");
      }
    }

    const savedCategories = localStorage.getItem("ss_categories");
    if (savedCategories) {
      try {
        setCategories(JSON.parse(savedCategories));
      } catch (e) {
        setCategories(CATEGORIES);
      }
    }

    const savedTx = localStorage.getItem("ss_transactions");
    if (savedTx) {
      try {
        setTransactions(JSON.parse(savedTx));
      } catch (e) {
        setTransactions(INITIAL_TRANSACTIONS);
      }
    } else {
      setTransactions(INITIAL_TRANSACTIONS);
    }

    const savedBudgets = localStorage.getItem("ss_budgets");
    if (savedBudgets) {
      try {
        setBudgets(JSON.parse(savedBudgets));
      } catch (e) {
        setBudgets(INITIAL_BUDGETS);
      }
    } else {
      setBudgets(INITIAL_BUDGETS);
    }

    const savedInstalled = localStorage.getItem("ss_installed");
    if (savedInstalled === "true") {
      setIsInstalled(true);
    }
  }, []);

  // Sync state helpers
  const saveTransactions = (newTx: Transaction[]) => {
    setTransactions(newTx);
    localStorage.setItem("ss_transactions", JSON.stringify(newTx));
  };

  const saveBudgets = (newBudgets: Budget[]) => {
    setBudgets(newBudgets);
    localStorage.setItem("ss_budgets", JSON.stringify(newBudgets));
  };

  const saveCategories = (newCategories: Record<string, CategoryInfo>) => {
    setCategories(newCategories);
    localStorage.setItem("ss_categories", JSON.stringify(newCategories));
  };

  const loginUser = (newUser: User) => {
    setUser(newUser);
    localStorage.setItem("ss_user", JSON.stringify(newUser));
    triggerToast(`Welcome back, ${newUser.name}! ≡ƒæï`);
  };

  const logoutUser = () => {
    setUser(null);
    localStorage.removeItem("ss_user");
    setAuthMode("landing");
    setOnboardingStep(0);
    triggerToast("Logged out successfully.", "info");
  };

  const triggerToast = (message: string, type: "success" | "info" | "warning" = "success") => {
    setToast({ message, type });
  };

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  useEffect(() => {
    if (pushNotification) {
      const timer = setTimeout(() => setPushNotification(null), 5500);
      return () => clearTimeout(timer);
    }
  }, [pushNotification]);

  // Scroll chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [aiMessages, isAiTyping]);

  // Initial Greet message for AI
  useEffect(() => {
    if (aiMessages.length === 0 && user) {
      setAiMessages([
        {
          id: "greet",
          sender: "ai",
          text: `≡ƒæï Hi ${user.name}! I am your SmartSpend AI Coach. I analyze your spending at ${user.college} and help you manage your Γé╣${user.allowance.toLocaleString()} allowance.\n\nAsk me something like:\n- *"Am I overspending on food?"*\n- *"What is my biggest expense this month?"*\n- *"Give me student budget tips."*`,
          timestamp: "09:40 AM"
        }
      ]);
    }
  }, [aiMessages, user]);

  // --- Financial Calculations ---
  const totals = useMemo(() => {
    let income = 0;
    let expense = 0;

    transactions.forEach(t => {
      if (t.type === "income") {
        income += t.amount;
      } else {
        expense += t.amount;
      }
    });

    const balance = income - expense;
    const savingsRate = income > 0 ? ((income - expense) / income) * 100 : 0;

    return {
      income,
      expense,
      balance,
      savingsRate: Math.max(0, savingsRate)
    };
  }, [transactions]);

  const categorySpending = useMemo(() => {
    const spending: Record<string, number> = {};

    // Initialize keys with current categories
    Object.keys(categories).forEach(cat => {
      spending[cat] = 0;
    });

    transactions.forEach(t => {
      if (t.type === "expense") {
        spending[t.category] = (spending[t.category] || 0) + t.amount;
      }
    });

    return spending;
  }, [transactions, categories]);

  const budgetAlerts = useMemo(() => {
    const alerts: { category: string; percent: number; limit: number; spent: number }[] = [];
    budgets.forEach(b => {
      const spent = categorySpending[b.category] || 0;
      const percent = b.limit > 0 ? (spent / b.limit) * 100 : 0;
      if (percent >= 80) {
        alerts.push({
          category: b.category,
          percent: Math.round(percent),
          limit: b.limit,
          spent
        });
      }
    });
    return alerts;
  }, [budgets, categorySpending]);

  // --- Dynamic Gamification: SmartScore & Badges ---
  const smartScore = useMemo(() => {
    let score = 650; // default base

    if (totals.income > 0) {
      if (totals.savingsRate > 40) score += 120;
      else if (totals.savingsRate > 20) score += 60;
      else if (totals.savingsRate < 5) score -= 90;
    } else {
      score -= 40;
    }

    let overLimitCount = 0;
    let nearLimitCount = 0;

    budgets.forEach(b => {
      const spent = categorySpending[b.category] || 0;
      const ratio = b.limit > 0 ? spent / b.limit : 0;
      if (ratio > 1.0) overLimitCount++;
      else if (ratio >= 0.8) nearLimitCount++;
    });

    score -= overLimitCount * 50;
    score -= nearLimitCount * 20;

    if (budgets.length > 0 && overLimitCount === 0 && nearLimitCount === 0) {
      score += 70; // perfect budget discipline
    }

    if (transactions.length >= 10) score += 40;
    else if (transactions.length >= 5) score += 20;
    else score -= 30;

    return Math.min(900, Math.max(300, score));
  }, [transactions, budgets, categorySpending, totals]);

  const userBadges = useMemo((): Badge[] => {
    const unlockedList: string[] = [];

    // Swiggy Slayer: Food spent is <= 80% and > 0
    const foodLimit = budgets.find(b => b.category === "Food")?.limit || 0;
    const foodSpent = categorySpending["Food"] || 0;
    if (foodSpent > 0 && foodLimit > 0 && foodSpent <= foodLimit * 0.8) {
      unlockedList.push("swiggy");
    }

    // Metro Master: Travel spent <= 80%
    const travelLimit = budgets.find(b => b.category === "Travel")?.limit || 0;
    const travelSpent = categorySpending["Travel"] || 0;
    if (travelSpent > 0 && travelLimit > 0 && travelSpent <= travelLimit * 0.8) {
      unlockedList.push("metro");
    }

    // Scholar: Academics expense >= 500
    const acadSpent = transactions
      .filter(t => t.category === "Academics" && t.type === "expense")
      .reduce((sum, t) => sum + t.amount, 0);
    if (acadSpent >= 500) {
      unlockedList.push("scholar");
    }

    // Savings Sensei: Savings rate >= 35% with recorded income
    if (totals.income > 0 && totals.savingsRate >= 35) {
      unlockedList.push("savings");
    }

    // Habitual Logger: 8+ transactions
    if (transactions.length >= 8) {
      unlockedList.push("habitual");
    }

    // Budget Ninja: All budgets under 100%
    const hasBudgets = budgets.length > 0;
    const allUnder = hasBudgets && budgets.every(b => (categorySpending[b.category] || 0) <= b.limit);
    if (allUnder) {
      unlockedList.push("ninja");
    }

    return BADGE_TEMPLATES.map(b => ({
      ...b,
      unlocked: unlockedList.includes(b.id)
    }));
  }, [transactions, budgets, categorySpending, totals]);

  // --- PDF Statement Generator ---
  const handlePDFExport = () => {
    const printWindow = window.open("", "_blank");
    if (!printWindow) {
      triggerToast("Popup blocked! Allow popups to export statement.", "warning");
      return;
    }

    const txRows = filteredTransactions
      .map(
        t => `
      <tr style="border-bottom: 1px solid #e2e8f0;">
        <td style="padding: 10px; font-size: 11px;">${t.date}</td>
        <td style="padding: 10px; font-size: 11px; font-weight: bold; color: #334155;">${t.category}</td>
        <td style="padding: 10px; font-size: 11px; color: #475569;">${t.note || "-"}</td>
        <td style="padding: 10px; font-size: 11px; text-transform: capitalize;">${t.type}</td>
        <td style="padding: 10px; font-size: 11px; font-weight: bold; text-align: right; color: ${
          t.type === "income" ? "#10b981" : "#1e293b"
        }">
          ${t.type === "income" ? "+" : "-"}Γé╣${t.amount.toLocaleString()}
        </td>
      </tr>
    `
      )
      .join("");

    printWindow.document.write(`
      <html>
        <head>
          <title>SmartSpend Financial Statement - ${user?.name || "Student"}</title>
          <style>
            @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;750;800&display=swap');
            body { font-family: 'Inter', sans-serif; color: #1e293b; padding: 40px; margin: 0; background: #ffffff; }
            .header { display: flex; justify-content: space-between; border-bottom: 2px solid #f1f5f9; padding-bottom: 20px; margin-bottom: 30px; }
            .title { font-size: 26px; font-weight: 800; color: #4f46e5; letter-spacing: -0.025em; }
            .subtitle { font-size: 12px; color: #64748b; margin-top: 4px; font-weight: 500; }
            .meta { font-size: 11px; color: #475569; line-height: 1.6; text-align: right; }
            .grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; margin-bottom: 35px; }
            .summary-card { background: #f8fafc; border: 1px solid #e2e8f0; border-radius: 12px; padding: 16px; text-align: center; }
            .summary-label { font-size: 9px; color: #64748b; font-weight: 750; text-transform: uppercase; letter-spacing: 0.05em; }
            .summary-val { font-size: 20px; font-weight: 800; margin-top: 6px; }
            h3 { font-size: 14px; font-weight: 800; color: #0f172a; margin-top: 30px; margin-bottom: 15px; border-bottom: 1px solid #f1f5f9; padding-bottom: 8px; }
            table { width: 100%; border-collapse: collapse; margin-top: 10px; }
            th { background: #f8fafc; padding: 12px 10px; text-align: left; font-size: 10px; font-weight: 750; color: #475569; border-bottom: 2px solid #e2e8f0; text-transform: uppercase; }
            td { border-bottom: 1px solid #f1f5f9; }
            .footer { margin-top: 50px; font-size: 9px; color: #94a3b8; text-align: center; border-top: 1px solid #f1f5f9; padding-top: 15px; }
          </style>
        </head>
        <body>
          <div class="header">
            <div>
              <div class="title">≡ƒÆ╕ SmartSpend Report</div>
              <div class="subtitle">AI-Powered Personal Finance Tracker for College Students</div>
            </div>
            <div class="meta">
              <strong>Student:</strong> ${user?.name || "Aarav Mehta"}<br/>
              <strong>Campus:</strong> ${user?.college || "IIT Delhi"}<br/>
              <strong>Export Date:</strong> ${new Date().toLocaleDateString("en-IN", {
                year: "numeric",
                month: "long",
                day: "numeric"
              })}<br/>
              <strong>SmartScore:</strong> ${smartScore} / 900
            </div>
          </div>

          <div class="grid">
            <div class="summary-card">
              <div class="summary-label">Total Inflow (Stipend/Allowance)</div>
              <div class="summary-val" style="color: #10b981;">Γé╣${totals.income.toLocaleString()}</div>
            </div>
            <div class="summary-card">
              <div class="summary-label">Total Outflow (Canteen/Travel/Bills)</div>
              <div class="summary-val" style="color: #f43f5e;">Γé╣${totals.expense.toLocaleString()}</div>
            </div>
            <div class="summary-card">
              <div class="summary-label">Net Balance Saved</div>
              <div class="summary-val" style="color: #4f46e5;">Γé╣${totals.balance.toLocaleString()}</div>
            </div>
          </div>

          <h3>Itemized Transaction History</h3>
          <table>
            <thead>
              <tr>
                <th style="width: 15%">Date</th>
                <th style="width: 25%">Category</th>
                <th style="width: 35%">Description Note</th>
                <th style="width: 10%">Type</th>
                <th style="text-align: right; width: 15%">Amount</th>
              </tr>
            </thead>
            <tbody>
              ${txRows || '<tr><td colspan="5" style="text-align:center; padding:20px; color:#94a3b8;">No transactions logged for this period.</td></tr>'}
            </tbody>
          </table>

          <div class="footer">
            Generated via SmartSpend PWA. Data cached offline and processed securely. Keep saving smart! ≡ƒÄô
          </div>

          <script>
            window.onload = function() {
              window.print();
              setTimeout(function() { window.close(); }, 500);
            }
          </script>
        </body>
      </html>
    `);
    printWindow.document.close();
    triggerToast("PDF Statement ready! Opening printing dialog...", "success");
  };

  // --- CRUD Transactions ---
  const handleOpenAddModal = () => {
    setFormAmount("");
    setFormCategory(Object.keys(categories)[0] || "Food");
    setFormType("expense");
    setFormNote("");
    setFormDate(new Date().toISOString().split("T")[0]);
    setFormRecurring(false);
    setActiveEditingTransaction(null);
    setShowAddModal(true);
  };

  const handleOpenEditModal = (t: Transaction) => {
