      return;
    }

    if (activeEditingTransaction) {
      // Edit mode
      const oldTx = activeEditingTransaction;
      const updated = transactions.map(t => {
        if (t.id === oldTx.id) {
          return {
            ...t,
            amount: parsedAmt,
            category: formCategory,
            type: formType,
            note: formNote,
            date: formDate,
            recurring: formRecurring
          };
        }
        return t;
      });

      // Check for budget notifications
      if (formType === "expense") {
        const budgetLimit = budgets.find(b => b.category === formCategory)?.limit || 0;
        if (budgetLimit > 0) {
          const previousCategorySpent = categorySpending[formCategory] - oldTx.amount;
          const currentCategorySpent = previousCategorySpent + parsedAmt;
          checkAndTriggerPushNotification(formCategory, currentCategorySpent, budgetLimit);
        }
      }

      saveTransactions(updated);
      triggerToast(offlineMode ? "Offline: updated cached log!" : "Transaction updated successfully!");
