                    variant="ghost"
                    className="flex-1 h-9 rounded-xl text-slate-400 hover:text-slate-700"
                  >
                    Cancel
                  </Button>
                  <Button
                    type="submit"
                    className="flex-1 bg-violet-650 hover:bg-violet-755 text-white font-bold h-9 rounded-xl shadow-md shadow-violet-600/10"
