              <div className="absolute top-[-30%] right-[-10%] size-24 bg-violet-500/5 rounded-full blur-2xl"></div>

              <div className="size-11 rounded-2xl bg-violet-600 flex items-center justify-center font-extrabold text-base text-white mx-auto shadow shadow-violet-650/20">
