                >
                  Install
                </Button>
              </div>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

// --- CSV Helper ---
const handleCSVExport = () => {
  // Read local storage to fetch fresh transaction records
  const rawTx = localStorage.getItem("ss_transactions");
  let txList: Transaction[] = [];
  try {
    txList = rawTx ? JSON.parse(rawTx) : [];
  } catch (e) {
    txList = [];
  }

  if (txList.length === 0) {
    alert("No transactions to export");
    return;
  }

  let csvContent = "data:text/csv;charset=utf-8,";
  csvContent += "ID,Type,Category,Amount,Date,Note,Recurring\n";

  txList.forEach(t => {
    const row = `"${t.id}","${t.type}","${t.category}",${t.amount},"${t.date}","${(t.note || "").replace(/"/g, '""')}",${t.recurring}`;
    csvContent += row + "\n";
  });

  const encodedUri = encodeURI(csvContent);
  const link = document.createElement("a");
  link.setAttribute("href", encodedUri);
  link.setAttribute("download", `smartspend_transactions_${new Date().toISOString().split("T")[0]}.csv`);
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};
